fun solve(words: Array<String>): Array<Long> {
    val n = words.size
    val answer = LongArray(n)

    // Preprocess to build a trie for efficient prefix checking
    val trie = Trie()
    for (word in words) {
        trie.insert(word)
    }

    // For each index, simulate removal and compute the max prefix length
    for (i in 0 until n) {
        val tempWords = words.toMutableList()
        tempWords.removeAt(i)

        var maxPrefix = 0L
        for (j in 0 until tempWords.size - 1) {
            val prefix = getCommonPrefix(tempWords[j], tempWords[j + 1])
            maxPrefix = max(maxPrefix, prefix.length.toLong())
        }
        answer[i] = maxPrefix
    }

    return answer
}

class TrieNode {
    val children = HashMap<Char, TrieNode>()
}

class Trie {
    val root = TrieNode()

    fun insert(word: String) {
        var node = root
        for (c in word) {
            node.children.putIfAbsent(c, TrieNode())
            node = node.children[c]!!
        }
    }

    fun getCommonPrefix(s1: String, s2: String): String {
        var i = 0
        while (i < s1.length && i < s2.length && s1[i] == s2[i]) {
            i++
        }
        return s1.substring(0, i)
    }
}
